"use client";

import { Button } from "@workspace/ui/components/button";
import { Card, CardContent } from "@workspace/ui/components/card";
import { Textarea } from "@workspace/ui/components/textarea";
import { Send } from "lucide-react";
import { useCallback, useEffect, useRef, useState } from "react";
import { Streamdown } from "streamdown";
import { formatOrgDisplayName } from "@/features/organization/format-display-name";
import type { OrganizationCategory } from "@/features/organization-category/get-organization-categories";
import type { ChatTodo } from "../todos/get-todos";
import { TodoList } from "../todos/todo-list.client";

type Message = {
	id: string;
	role: "user" | "assistant";
	content: string;
};

type OrganizationByCategory = {
	categoryId: string;
	description: string;
	email: string;
	organizationId: string;
	name: string;
	url: string;
};

export function ChatRoom({
	categories,
	chatId,
	contactEmail,
	initialConsultedOrgIds,
	initialMessages,
	initialTodos,
	organizationsByCategory,
	referrerOrgName,
}: {
	categories: OrganizationCategory[];
	chatId: string;
	contactEmail: string | null;
	initialConsultedOrgIds: string[];
	initialMessages: Message[];
	initialTodos: ChatTodo[];
	organizationsByCategory: OrganizationByCategory[];
	referrerOrgName: string | null;
}) {
	const [messages, setMessages] = useState<Message[]>(initialMessages);
	const [input, setInput] = useState("");
	const [isStreaming, setIsStreaming] = useState(false);
	const [errorMessage, setErrorMessage] = useState<string | null>(null);
	const [todos, setTodos] = useState<ChatTodo[]>(initialTodos);
	const [storedEmail, setStoredEmail] = useState<string | null>(contactEmail);
	const [consultedOrgIds, setConsultedOrgIds] = useState<string[]>(
		initialConsultedOrgIds,
	);
	const messagesEndRef = useRef<HTMLDivElement | null>(null);

	useEffect(() => {
		messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
	}, []);

	const refreshTodos = useCallback(async () => {
		try {
			const todosRes = await fetch(`/api/chats/${chatId}/todos`, {
				cache: "no-store",
			});
			if (todosRes.ok) {
				const json = (await todosRes.json()) as { todos: ChatTodo[] };
				setTodos(json.todos);
			}
		} catch {
			// 失敗しても本流は止めない
		}
	}, [chatId]);

	const refreshConsultedOrgIds = useCallback(async () => {
		try {
			const res = await fetch(`/api/chats/${chatId}/consultations`, {
				cache: "no-store",
			});
			if (res.ok) {
				const json = (await res.json()) as { consultedOrgIds: string[] };
				setConsultedOrgIds(json.consultedOrgIds);
			}
		} catch {
			// 失敗しても本流は止めない
		}
	}, [chatId]);

	async function handleSubmit(event: React.FormEvent<HTMLFormElement>) {
		event.preventDefault();
		const message = input.trim();
		if (!message || isStreaming) {
			return;
		}

		setErrorMessage(null);
		setInput("");
		const userMessageId = crypto.randomUUID();
		setMessages((prev) => [
			...prev,
			{ content: message, id: userMessageId, role: "user" },
		]);

		setIsStreaming(true);
		const assistantId = crypto.randomUUID();
		setMessages((prev) => [
			...prev,
			{ content: "", id: assistantId, role: "assistant" },
		]);

		try {
			const response = await fetch(`/api/chats/${chatId}/messages`, {
				body: JSON.stringify({ message }),
				headers: { "content-type": "application/json" },
				method: "POST",
			});

			if (!response.ok || !response.body) {
				throw new Error("チャット応答の取得に失敗しました");
			}

			const reader = response.body.getReader();
			const decoder = new TextDecoder();
			let assistantText = "";
			while (true) {
				const { done, value } = await reader.read();
				if (done) {
					break;
				}
				assistantText += decoder.decode(value, { stream: true });
				setMessages((prev) =>
					prev.map((m) =>
						m.id === assistantId ? { ...m, content: assistantText } : m,
					),
				);
			}

			// TODO 一覧を再取得（ツール経由の done 更新も反映するためキャッシュ無効化）
			await refreshTodos();
		} catch (error) {
			setErrorMessage(
				error instanceof Error
					? error.message
					: "チャット応答の取得に失敗しました",
			);
			setMessages((prev) => prev.filter((m) => m.id !== assistantId));
		} finally {
			setIsStreaming(false);
			setTimeout(() => {
				messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
			}, 50);
		}
	}

	return (
		<div className="flex h-full flex-col gap-3 lg:flex-row">
			<Card className="flex flex-1 min-h-0 flex-col">
				<CardContent className="flex flex-1 min-h-0 flex-col gap-3 p-4">
					<p className="text-xs text-muted-foreground">
						紹介元: {formatOrgDisplayName(referrerOrgName)}
					</p>
					<div className="flex-1 overflow-y-auto rounded-md border p-3 flex flex-col gap-3">
						{messages.length === 0 && (
							<p className="text-sm text-muted-foreground">
								こんにちは。相続や終活、相続後の資産活用についてご相談ください。
								<br />
								現在の状況を教えていただけますか？
							</p>
						)}
						{messages.map((message) => (
							<div
								className={
									message.role === "user"
										? "self-end max-w-[80%] rounded-lg bg-primary text-primary-foreground px-3 py-2 whitespace-pre-wrap"
										: "self-start max-w-[85%] rounded-lg bg-muted px-3 py-2"
								}
								key={message.id}
							>
								{message.role === "assistant" ? (
									message.content ? (
										<div className="prose prose-sm max-w-none dark:prose-invert prose-p:my-2 prose-headings:my-3">
											<Streamdown>{message.content}</Streamdown>
										</div>
									) : isStreaming ? (
										"考え中…"
									) : (
										""
									)
								) : (
									<span className="whitespace-pre-wrap">{message.content}</span>
								)}
							</div>
						))}
						<div ref={messagesEndRef} />
					</div>
					{errorMessage && (
						<p className="text-sm text-destructive" role="alert">
							{errorMessage}
						</p>
					)}
					<form className="flex flex-col gap-2" onSubmit={handleSubmit}>
						<Textarea
							className="min-h-[80px]"
							disabled={isStreaming}
							onChange={(e) => setInput(e.target.value)}
							onKeyDown={(e) => {
								if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) {
									e.preventDefault();
									(
										e.currentTarget.form as HTMLFormElement | null
									)?.requestSubmit();
								}
							}}
							placeholder="メッセージを入力 (Cmd/Ctrl + Enter で送信)"
							value={input}
						/>
						<div className="flex justify-end">
							<Button
								disabled={isStreaming || input.trim().length === 0}
								isProcessing={isStreaming}
								processingLabel="応答中"
								type="submit"
							>
								<Send className="size-4" />
								送信
							</Button>
						</div>
					</form>
				</CardContent>
			</Card>
			<aside className="lg:w-[360px] flex flex-col gap-3 min-h-0">
				<TodoList
					categories={categories}
					chatId={chatId}
					consultedOrgIds={consultedOrgIds}
					initialEmail={storedEmail}
					onConsulted={refreshConsultedOrgIds}
					onEmailRegistered={(email) => setStoredEmail(email)}
					onTodosRefresh={refreshTodos}
					organizationsByCategory={organizationsByCategory}
					todos={todos}
				/>
			</aside>
		</div>
	);
}

