1	import { notFound } from "next/navigation";
2	import { isChatPublicAccessExpired } from "@/features/chat/access-control";
3	import { getChat, touchChatLastAccessedAt } from "@/features/chat/get-chat";
4	import { getChatMessages } from "@/features/chat/messages/get-messages";
5	import { ChatRoom } from "@/features/chat/room/chat-room.client";
6	import { getOrganizationsByCategory } from "@/features/chat/room/get-chat-context";
7	import { getChatTodos } from "@/features/chat/todos/get-todos";
8	import { getConsultedOrgIdsByChat } from "@/features/consultation/list/get-consultations-by-chat";
9	import { getOrganizationCategories } from "@/features/organization-category/get-organization-categories";
10	
11	export async function ChatRoomContainer({ chatId }: { chatId: string }) {
12		const chat = await getChat(chatId);
13		if (!chat) {
14			notFound();
15		}
16	
17		if (isChatPublicAccessExpired(chat.lastAccessedAt)) {
18			return (
19				<div className="mt-8 max-w-2xl mx-auto rounded-md border p-6">
20					<h2 className="text-lg font-semibold mb-2">
21						このチャットはアクセス期限が切れました
22					</h2>
23					<p className="text-sm text-muted-foreground">
24						最終アクセスから 1
25						週間以上経過したため、公開アクセスを停止しています。
26						チャット履歴は管理者・紹介組織からは引き続き確認できます。
27					</p>
28				</div>
29			);
30		}
31	
32		await touchChatLastAccessedAt(chatId);
33	
34		const [
35			messages,
36			todos,
37			categories,
38			organizationsByCategory,
39			consultedOrgIds,
40		] = await Promise.all([
41			getChatMessages(chatId),
42			getChatTodos(chatId),
43			getOrganizationCategories(),
44			getOrganizationsByCategory(),
45			getConsultedOrgIdsByChat(chatId),
46		]);
47	
48		const initialMessages = messages
49			.filter((m) => m.role === "user" || m.role === "assistant")
50			.map((m) => ({
51				content: m.content,
52				id: String(m.messageId),
53				role: m.role as "user" | "assistant",
54			}));
55	
56		return (
57			<ChatRoom
58				categories={categories}
59				chatId={chatId}
60				contactEmail={chat.contactEmail}
61				initialConsultedOrgIds={consultedOrgIds}
62				initialMessages={initialMessages}
63				initialTodos={todos}
64				organizationsByCategory={organizationsByCategory}
65				referrerOrgName={chat.referrerOrgName}
66			/>
67		);
68	}
