"use client";

import { Button } from "@workspace/ui/components/button";
import { useState } from "react";
import { startChatAction } from "@/features/chat/start/start-chat.action";

export function StartChatButton({
	organizationId,
}: {
	organizationId: string | null;
}) {
	const [submitting, setSubmitting] = useState(false);
	const [error, setError] = useState<string | null>(null);

	async function handleStart() {
		if (!organizationId) {
			setError("紹介組織が指定されていないため、相談を開始できません。");
			return;
		}
		setSubmitting(true);
		setError(null);
		const result = await startChatAction({ organizationId });
		if (!result.success) {
			setError(result.error || "相談の開始に失敗しました");
			setSubmitting(false);
		}
	}

	return (
		<div className="flex flex-col gap-2">
			<Button
				disabled={submitting || !organizationId}
				isProcessing={submitting}
				onClick={handleStart}
				processingLabel="準備中"
				size="lg"
			>
				相談を開始する
			</Button>
			{error && (
				<p className="text-sm text-destructive" role="alert">
					{error}
				</p>
			)}
		</div>
	);
}

