1	"use client";
2	
3	import { valibotResolver } from "@hookform/resolvers/valibot";
4	import { Badge } from "@workspace/ui/components/badge";
5	import { Button } from "@workspace/ui/components/button";
6	import {
7		Card,
8		CardContent,
9		CardHeader,
10		CardTitle,
11	} from "@workspace/ui/components/card";
12	import {
13		Dialog,
14		DialogContent,
15		DialogFooter,
16		DialogHeader,
17		DialogTitle,
18	} from "@workspace/ui/components/dialog";
19	import {
20		Form,
21		FormControl,
22		FormField,
23		FormItem,
24		FormLabel,
25		FormMessage,
26	} from "@workspace/ui/components/form";
27	import { Input } from "@workspace/ui/components/input";
28	import { Building2, Check, CheckCircle2, Mail } from "lucide-react";
29	import { useState, useTransition } from "react";
30	import { useForm } from "react-hook-form";
31	import * as v from "valibot";
32	import { requestConsultationAction } from "@/features/consultation/request/request-consultation.action";
33	import type { OrganizationCategory } from "@/features/organization-category/get-organization-categories";
34	import type { ChatTodo } from "./get-todos";
35	import { updateTodoDoneAction } from "./update-todo-done.action";
36	
37	type OrganizationByCategory = {
38		categoryId: string;
39		description: string;
40		email: string;
41		organizationId: string;
42		name: string;
43		url: string;
44	};
45	
46	const PHASE_LABELS: { color: string; label: string }[] = [
47		{ color: "bg-indigo-100 text-indigo-900", label: "終活" },
48		{ color: "bg-red-100 text-red-900", label: "緊急 (7日)" },
49		{ color: "bg-orange-100 text-orange-900", label: "高 (14日)" },
50		{ color: "bg-amber-100 text-amber-900", label: "中 (3ヶ月)" },
51		{ color: "bg-lime-100 text-lime-900", label: "中 (4ヶ月)" },
52		{ color: "bg-sky-100 text-sky-900", label: "最重要 (10ヶ月)" },
53		{ color: "bg-pink-100 text-pink-900", label: "資産活用" },
54	];
55	
56	const formSchema = v.object({
57		email: v.pipe(
58			v.string("メールアドレスを入力してください"),
59			v.minLength(1, "メールアドレスを入力してください"),
60			v.email("正しいメールアドレス形式で入力してください"),
61			v.maxLength(254, "メールアドレスは254文字以内で入力してください"),
62		),
63	});
64	
65	type FormValues = v.InferOutput<typeof formSchema>;
66	
67	export function TodoList({
68		categories,
69		chatId,
70		consultedOrgIds,
71		initialEmail,
72		onConsulted,
73		onEmailRegistered,
74		onTodosRefresh,
75		organizationsByCategory,
76		todos,
77	}: {
78		categories: OrganizationCategory[];
79		chatId: string;
80		consultedOrgIds: string[];
81		initialEmail: string | null;
82		onConsulted: () => void | Promise<void>;
83		onEmailRegistered: (email: string) => void;
84		onTodosRefresh: () => void | Promise<void>;
85		organizationsByCategory: OrganizationByCategory[];
86		todos: ChatTodo[];
87	}) {
88		const [dialogTarget, setDialogTarget] = useState<{
89			todoId: string;
90			categoryId: string;
91			organizationId: string;
92			organizationName: string;
93			title: string;
94		} | null>(null);
95		const [infoTarget, setInfoTarget] = useState<OrganizationByCategory | null>(
96			null,
97		);
98		const [submitting, setSubmitting] = useState(false);
99		const [successMessage, setSuccessMessage] = useState<string | null>(null);
100		const [errorMessage, setErrorMessage] = useState<string | null>(null);
101		const [optimisticDone, setOptimisticDone] = useState<Record<string, boolean>>(
102			{},
103		);
104		const [, startTransition] = useTransition();
105	
106		function clearOptimistic(todoId: string) {
107			setOptimisticDone((prev) => {
108				if (!(todoId in prev)) {
109					return prev;
110				}
111				const { [todoId]: _omit, ...rest } = prev;
112				return rest;
113			});
114		}
115	
116		function toggleDone(todo: ChatTodo) {
117			const nextDone = !(optimisticDone[todo.todoId] ?? todo.done);
118			setOptimisticDone((prev) => ({ ...prev, [todo.todoId]: nextDone }));
119			startTransition(async () => {
120				await updateTodoDoneAction({
121					chatId,
122					done: nextDone,
123					todoId: todo.todoId,
124				});
125				// サーバー値を取り直してから optimistic をクリア（props 反映後に切替）
126				await onTodosRefresh();
127				clearOptimistic(todo.todoId);
128			});
129		}
130	
131		const form = useForm<FormValues>({
132			defaultValues: { email: initialEmail ?? "" },
133			resolver: valibotResolver(formSchema),
134		});
135	
136		function findOrgForCategory(categoryId: string) {
137			return organizationsByCategory.find((org) => org.categoryId === categoryId);
138		}
139	
140		function categoryName(categoryId: string | null): string {
141			if (!categoryId) {
142				return "";
143			}
144			return categories.find((c) => c.categoryId === categoryId)?.name ?? "";
145		}
146	
147		function openConsultDialog(todo: ChatTodo) {
148			if (!todo.suggestedCategoryId) {
149				return;
150			}
151			const org = findOrgForCategory(todo.suggestedCategoryId);
152			if (!org) {
153				return;
154			}
155			setDialogTarget({
156				categoryId: todo.suggestedCategoryId,
157				organizationId: org.organizationId,
158				organizationName: org.name,
159				title: todo.title,
160				todoId: todo.todoId,
161			});
162			setErrorMessage(null);
163			setSuccessMessage(null);
164		}
165	
166		async function handleSubmit(values: FormValues) {
167			if (!dialogTarget) {
168				return;
169			}
170			setSubmitting(true);
171			setErrorMessage(null);
172	
173			const result = await requestConsultationAction({
174				chatId,
175				contactEmail: initialEmail ? undefined : values.email,
176				targetOrgId: dialogTarget.organizationId,
177				todoId: dialogTarget.todoId,
178			});
179	
180			setSubmitting(false);
181			if (!result.success) {
182				setErrorMessage(result.error || "相談の送信に失敗しました");
183				return;
184			}
185	
186			onEmailRegistered(values.email);
187			await onConsulted();
188			setSuccessMessage(
189				`${dialogTarget.organizationName}に相談メールを送信しました。`,
190			);
191			setTimeout(() => {
192				setDialogTarget(null);
193			}, 1500);
194		}
195	
196		return (
197			<>
198				<Card className="flex min-h-0 flex-col">
199					<CardHeader>
200						<CardTitle className="text-base">対応タスク</CardTitle>
201					</CardHeader>
202					<CardContent className="flex-1 overflow-y-auto flex flex-col gap-2">
203						{todos.length === 0 && (
204							<p className="text-sm text-muted-foreground">
205								会話が進むとここに具体的な TODO が表示されます。
206							</p>
207						)}
208						{todos.map((todo) => {
209							const phase = PHASE_LABELS[todo.priority] ?? PHASE_LABELS[0];
210							const org = todo.suggestedCategoryId
211								? findOrgForCategory(todo.suggestedCategoryId)
212								: undefined;
213							const canConsult = !!org && !!org.email;
214							const isConsulted =
215								!!org && consultedOrgIds.includes(org.organizationId);
216							const isDone = optimisticDone[todo.todoId] ?? todo.done;
217							return (
218								<div
219									className={`rounded-md border p-3 flex flex-col gap-2 ${
220										isDone ? "bg-muted/40 opacity-70" : ""
221									}`}
222									key={todo.todoId}
223								>
224									<div className="flex items-start gap-2">
225										<label
226											aria-label={isDone ? "完了を取り消す" : "完了としてマーク"}
227											className={`mt-0.5 relative flex size-5 shrink-0 cursor-pointer items-center justify-center rounded border transition-colors ${
228												isDone
229													? "border-primary bg-primary text-primary-foreground"
230													: "border-input bg-background hover:bg-accent"
231											}`}
232										>
233											<input
234												checked={isDone}
235												className="sr-only"
236												onChange={() => toggleDone(todo)}
237												type="checkbox"
238											/>
239											{isDone && <Check className="size-3.5" />}
240										</label>
241										<div className="flex flex-1 flex-col gap-2 min-w-0">
242											<div className="flex flex-wrap items-center gap-2">
243												{phase && (
244													<Badge className={phase.color}>{phase.label}</Badge>
245												)}
246												{todo.suggestedCategoryId && (
247													<Badge variant="outline">
248														{categoryName(todo.suggestedCategoryId)}
249													</Badge>
250												)}
251											</div>
252											<p
253												className={`text-sm font-medium ${
254													isDone ? "line-through" : ""
255												}`}
256											>
257												{todo.title}
258											</p>
259											{todo.description && (
260												<p className="text-xs text-muted-foreground whitespace-pre-wrap">
261													{todo.description}
262												</p>
263											)}
264											{canConsult &&
265												!isDone &&
266												(isConsulted ? (
267													<Button
268														disabled
269														size="sm"
270														type="button"
271														variant="outline"
272													>
273														<CheckCircle2 className="size-4" />
274														相談済み
275													</Button>
276												) : (
277													<div className="flex flex-col gap-1 items-start">
278														<button
279															className="text-xs text-primary inline-flex items-center gap-1 underline-offset-2 hover:underline"
280															onClick={() => setInfoTarget(org)}
281															type="button"
282														>
283															<Building2 className="size-3.5" />
284															相談先企業情報
285														</button>
286														<Button
287															onClick={() => openConsultDialog(todo)}
288															size="sm"
289															variant="outline"
290														>
291															<Mail className="size-4" />
292															相談する
293														</Button>
294														<p className="text-xs text-muted-foreground">
295															クリックすると提携企業からご連絡を差し上げます
296														</p>
297													</div>
298												))}
299										</div>
300									</div>
301								</div>
302							);
303						})}
304					</CardContent>
305				</Card>
306	
307				<Dialog
308					onOpenChange={(open) => !open && setDialogTarget(null)}
309					open={dialogTarget !== null}
310				>
311					<DialogContent>
312						<DialogHeader>
313							<DialogTitle>
314								{dialogTarget?.organizationName} に相談する
315							</DialogTitle>
316						</DialogHeader>
317						<Form {...form}>
318							<form
319								className="flex flex-col gap-4"
320								noValidate
321								onSubmit={form.handleSubmit(handleSubmit)}
322							>
323								<p className="text-sm text-muted-foreground">
324									あなたのメールアドレスを {dialogTarget?.organizationName}
325									に共有して、相談を開始します。
326								</p>
327								<FormField
328									control={form.control}
329									name="email"
330									render={({ field }) => (
331										<FormItem>
332											<FormLabel>メールアドレス</FormLabel>
333											<FormControl>
334												<Input
335													autoComplete="email"
336													disabled={submitting || !!initialEmail}
337													type="email"
338													{...field}
339												/>
340											</FormControl>
341											{initialEmail && (
342												<p className="text-xs text-muted-foreground">
343													登録済みのメールアドレスを使用します。
344												</p>
345											)}
346											<FormMessage />
347										</FormItem>
348									)}
349								/>
350								{errorMessage && (
351									<p className="text-sm text-destructive" role="alert">
352										{errorMessage}
353									</p>
354								)}
355								{successMessage && (
356									<p className="text-sm text-emerald-700" role="status">
357										{successMessage}
358									</p>
359								)}
360								<DialogFooter>
361									<Button
362										disabled={submitting}
363										onClick={() => setDialogTarget(null)}
364										type="button"
365										variant="outline"
