import { Sparkle } from "lucide-react";
import { StartChatButton } from "@/app/(public)/chats/_components/start-chat-button.client";
import { getOrganizationDetail } from "@/features/organization/detail/get-organization-detail";

export async function ChatLandingContainer({
	org,
}: {
	org: string | undefined;
}) {
	const organization = org ? await getOrganizationDetail(org) : null;

	return (
		<div className="flex flex-col gap-10 [animation:fade-up_0.9s_ease-out_both]">
			<style>{`
				@keyframes fade-up {
					from { opacity: 0; transform: translateY(8px); }
					to { opacity: 1; transform: translateY(0); }
				}
				@keyframes shimmer {
					0%, 100% { opacity: 0.45; }
					50% { opacity: 0.85; }
				}
			`}</style>

			<header className="flex flex-col items-center gap-6 pt-2 text-center">
				<div className="flex items-center gap-3">
					<span className="h-px w-10 bg-gradient-to-r from-transparent to-[#B89968]/70" />
					<Sparkle
						className="size-3.5 text-[#B89968]"
						style={{ animation: "shimmer 4s ease-in-out infinite" }}
					/>
					<span className="h-px w-10 bg-gradient-to-l from-transparent to-[#B89968]/70" />
				</div>
				<p className="font-[family-name:var(--font-mincho)] text-xs tracking-[0.45em] text-[#6B6760]">
					O M I O K U R I &nbsp;・&nbsp; S U P P O R T
				</p>
				<h1 className="font-[family-name:var(--font-mincho)] text-[2.1rem] font-medium leading-[1.7] tracking-wider text-[#2A2622] sm:text-[2.6rem]">
					大切な方を想う、
					<br />
					その一歩に寄り添う。
				</h1>
				<p className="max-w-md font-[family-name:var(--font-sans-jp)] text-sm leading-[2.1] text-[#5C5852]">
					お見送りサポートチャットへ、ようこそ。
					<br />
					終活、ご相続のお手続き、その後の暮らしのことまで。
					<br />
					AI コンシェルジュが、静かに整理のお手伝いをいたします。
				</p>
			</header>

			<section className="relative">
				<div
					aria-hidden
					className="absolute -inset-px rounded-[2px] bg-gradient-to-br from-[#D7C49E]/40 via-transparent to-[#D7C49E]/40"
				/>
				<div className="relative flex flex-col gap-8 bg-[#FFFDF8]/85 px-6 py-10 backdrop-blur-sm sm:px-10 sm:py-12">
					<CornerMark className="absolute left-3 top-3" placement="tl" />
					<CornerMark className="absolute right-3 top-3" placement="tr" />
					<CornerMark className="absolute bottom-3 left-3" placement="bl" />
					<CornerMark className="absolute bottom-3 right-3" placement="br" />

					{organization ? (
						<div className="flex flex-col gap-2">
							<span className="font-[family-name:var(--font-mincho)] text-[0.7rem] tracking-[0.3em] text-[#B89968]">
								ご紹介元
							</span>
							<p className="font-[family-name:var(--font-mincho)] text-lg text-[#2A2622]">
								{organization.name}{" "}
								<span className="text-sm text-[#6B6760]">様</span>
							</p>
							<p className="text-xs leading-relaxed text-[#6B6760]">
								上記の組織よりご案内を受けてお越しいただきました。
							</p>
						</div>
					) : (
						<div className="flex flex-col gap-2 border-l-2 border-[#D9A199]/60 pl-4">
							<span className="font-[family-name:var(--font-mincho)] text-[0.7rem] tracking-[0.3em] text-[#A87268]">
								お知らせ
							</span>
							<p className="text-sm leading-relaxed text-[#5C5852]">
								ご紹介元の指定がございません。このままご相談を始めることもできますが、
								<wbr />
								ご紹介情報は記録されません。
							</p>
						</div>
					)}

					<div className="flex flex-col gap-3">
						<h2 className="font-[family-name:var(--font-mincho)] text-base text-[#2A2622]">
							ご相談できること
						</h2>
						<ul className="grid gap-2.5 text-sm text-[#5C5852]">
							{[
								"終活のご準備、おひとりの場合のお備え",
								"ご逝去後のお手続き、ご相続のご整理",
								"ご相続後の暮らし・資産のご活用",
							].map((item) => (
								<li className="flex items-start gap-3" key={item}>
									<span className="mt-2 h-px w-3 shrink-0 bg-[#B89968]" />
									<span className="leading-relaxed">{item}</span>
								</li>
							))}
						</ul>
					</div>

					<div className="relative overflow-hidden rounded-sm bg-[#FAF3E6]/60 px-5 py-4 text-[0.78rem] leading-[1.9] text-[#6B5A3F]">
						<div className="absolute left-0 top-0 h-full w-[2px] bg-gradient-to-b from-[#B89968] via-[#D9A199]/80 to-[#B89968]" />
