import { Skeleton } from "@workspace/ui/components/skeleton";
import type { Metadata } from "next";
import { Noto_Sans_JP, Shippori_Mincho } from "next/font/google";
import { Suspense } from "react";
import { ChatRoomContainer } from "@/features/chat/room/chat-room.server";

const mincho = Shippori_Mincho({
	display: "swap",
	subsets: ["latin"],
	variable: "--font-mincho",
	weight: ["400", "500", "600"],
});

const sans = Noto_Sans_JP({
	display: "swap",
	subsets: ["latin"],
	variable: "--font-sans-jp",
	weight: ["300", "400", "500"],
});

export const metadata: Metadata = {
	title: "お見送りサポートチャット",
};

export default function Page({ params }: PageProps<"/chats/[chatId]">) {
	const chatIdPromise = params.then((p) => p.chatId);

	return (
		<div
			className={`${mincho.variable} ${sans.variable} relative h-dvh overflow-hidden bg-[#FAF7F1] text-[#2A2622]`}
		>
			<div
				aria-hidden
				className="pointer-events-none absolute inset-0 opacity-60"
				style={{
					backgroundImage:
						"radial-gradient(1000px 500px at 90% -5%, rgba(217, 161, 153, 0.14), transparent 60%), radial-gradient(800px 500px at -5% 105%, rgba(91, 123, 139, 0.12), transparent 60%)",
				}}
			/>
			<div
				aria-hidden
				className="pointer-events-none absolute inset-0 opacity-[0.35] mix-blend-multiply"
				style={{
					backgroundImage:
						"url(\"data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='160' height='160'><filter id='n'><feTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='2' stitchTiles='stitch'/><feColorMatrix values='0 0 0 0 0.55  0 0 0 0 0.50  0 0 0 0 0.42  0 0 0 0.16 0'/></filter><rect width='100%25' height='100%25' filter='url(%23n)'/></svg>\")",
				}}
			/>

			<div className="relative mx-auto flex h-full w-full max-w-6xl flex-col px-4 py-4 sm:px-6">
				<header className="flex shrink-0 items-center justify-between border-b border-[#D7C49E]/40 pb-3">
					<div className="flex items-center gap-3">
						<span
							aria-hidden
							className="h-7 w-px bg-gradient-to-b from-transparent via-[#B89968] to-transparent"
						/>
						<div className="flex flex-col">
							<span className="font-[family-name:var(--font-mincho)] text-[0.6rem] tracking-[0.4em] text-[#8A867F]">
								O M I O K U R I
							</span>
							<h1 className="font-[family-name:var(--font-mincho)] text-base leading-tight tracking-wider text-[#2A2622] sm:text-lg">
								お見送りサポートチャット
							</h1>
						</div>
					</div>
					<div className="hidden items-center gap-2 sm:flex">
						<span className="size-1.5 rounded-full bg-[#B89968]/70" />
						<span className="font-[family-name:var(--font-mincho)] text-[0.65rem] tracking-[0.35em] text-[#6B6760]">
							静 か な お 部 屋
						</span>
					</div>
				</header>

				<div className="mt-4 min-h-0 flex-1">
					<Suspense
						fallback={
							<div className="flex h-full items-center justify-center">
								<Skeleton className="h-full w-full bg-[#EDE6D9]/70" />
							</div>
						}
					>
						<ChatRoomWrapper chatIdPromise={chatIdPromise} />
					</Suspense>
				</div>
			</div>
		</div>
	);
}

async function ChatRoomWrapper({
	chatIdPromise,
}: {
	chatIdPromise: Promise<string>;
}) {
	const chatId = await chatIdPromise;
	return <ChatRoomContainer chatId={chatId} />;
}

