								"ご相続後の暮らし・資産のご活用",
							].map((item) => (
								<li className="flex items-start gap-3" key={item}>
									<span className="mt-2 h-px w-3 shrink-0 bg-[#B89968]" />
									<span className="leading-relaxed">{item}</span>
								</li>
							))}
						</ul>
					</div>

					<div className="relative overflow-hidden rounded-sm bg-[#FAF3E6]/60 px-5 py-4 text-[0.78rem] leading-[1.9] text-[#6B5A3F]">
						<div className="absolute left-0 top-0 h-full w-[2px] bg-gradient-to-b from-[#B89968] via-[#D9A199]/80 to-[#B89968]" />
						<p className="mb-2">
							本サービスは主に
							<span className="text-[#2A2622]">千葉県にお住まいの方</span>
							を対象としています。
						</p>
						<p>
							お話の中では、氏名・ご住所・お電話番号・口座情報など
							<span className="text-[#2A2622]">個人を特定できる情報</span>
							のご入力はお控えくださいませ。
						</p>
					</div>

					<div className="flex flex-col items-center gap-4 pt-2">
						<StartChatButton
							organizationId={organization?.organizationId ?? null}
						/>
						<p className="text-center text-[0.7rem] leading-relaxed text-[#8A867F]">
							お渡しするチャット URL より、いつでも続きから
							<br className="sm:hidden" />
							ご相談いただけます。
							<br />
							（最終ご利用より 1 週間で公開アクセスは閉じられます）
						</p>
					</div>
				</div>
			</section>

			<footer className="flex items-center justify-center gap-3 pb-4 opacity-70">
				<span className="h-px w-6 bg-[#B89968]/50" />
				<span className="font-[family-name:var(--font-mincho)] text-[0.65rem] tracking-[0.4em] text-[#8A867F]">
					しずかに、ともに
				</span>
				<span className="h-px w-6 bg-[#B89968]/50" />
			</footer>
		</div>
	);
}

function CornerMark({
	className,
	placement,
}: {
	className?: string;
	placement: "tl" | "tr" | "bl" | "br";
}) {
	const lines: Record<typeof placement, string> = {
		bl: "border-b border-l",
		br: "border-b border-r",
		tl: "border-l border-t",
		tr: "border-r border-t",
	};
	return (
		<span
			aria-hidden
			className={`size-4 border-[#B89968]/60 ${lines[placement]} ${className ?? ""}`}
		/>
	);
}

import { Skeleton } from "@workspace/ui/components/skeleton";
import type { Metadata } from "next";
import { Suspense } from "react";
import { ChatRoomContainer } from "@/features/chat/room/chat-room.server";

export const metadata: Metadata = {
	title: "お見送りサポートチャット",
};

const MINCHO_FAMILY =
	'"Hiragino Mincho ProN", "Hiragino Mincho Pro", "Yu Mincho", YuMincho, "Noto Serif JP", "Times New Roman", serif';
const SANS_JP_FAMILY =
	'"Hiragino Kaku Gothic ProN", "Hiragino Sans", "Yu Gothic", YuGothic, "Noto Sans JP", -apple-system, BlinkMacSystemFont, sans-serif';

export default function Page({ params }: PageProps<"/chats/[chatId]">) {
	const chatIdPromise = params.then((p) => p.chatId);

	return (
		<div
			className="relative h-dvh overflow-hidden bg-[#FAF7F1] text-[#1F1B17]"
			style={
				{
					"--font-mincho": MINCHO_FAMILY,
					"--font-sans-jp": SANS_JP_FAMILY,
				} as React.CSSProperties
			}
		>
			<div
				aria-hidden
				className="pointer-events-none fixed inset-0 -z-10 bg-[#FAF7F1]"
			/>
			<div
				aria-hidden
				className="pointer-events-none fixed inset-0 -z-10 opacity-60"
				style={{
					backgroundImage:
						"radial-gradient(1000px 500px at 90% -5%, rgba(217, 161, 153, 0.14), transparent 60%), radial-gradient(800px 500px at -5% 105%, rgba(91, 123, 139, 0.12), transparent 60%)",
				}}
			/>
			<div
				aria-hidden
				className="pointer-events-none fixed inset-0 -z-10 opacity-[0.35] mix-blend-multiply"
				style={{
					backgroundImage:
						"url(\"data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='160' height='160'><filter id='n'><feTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='2' stitchTiles='stitch'/><feColorMatrix values='0 0 0 0 0.55  0 0 0 0 0.50  0 0 0 0 0.42  0 0 0 0.16 0'/></filter><rect width='100%25' height='100%25' filter='url(%23n)'/></svg>\")",
				}}
			/>

			<div className="relative mx-auto flex h-full w-full max-w-6xl flex-col px-4 py-4 sm:px-6">
				<header className="flex shrink-0 items-center justify-between border-b border-[#D7C49E]/40 pb-3">
