					<Suspense
						fallback={
							<div className="flex h-full items-center justify-center">
								<Skeleton className="h-full w-full bg-[#EDE6D9]/70" />
							</div>
						}
					>
						<ChatRoomWrapper chatIdPromise={chatIdPromise} />
					</Suspense>
				</div>
			</div>
		</div>
