					}
				>
					<ChatRoomWrapper chatIdPromise={chatIdPromise} />
				</Suspense>
			</div>
		</div>
	);
}

async function ChatRoomWrapper({
	chatIdPromise,
}: {
	chatIdPromise: Promise<string>;
}) {
	const chatId = await chatIdPromise;
	return <ChatRoomContainer chatId={chatId} />;
}

